#include<bits/stdc++.h>
using namespace std;
const int N=100005;
int dp[N],n,a[N],ans;
vector<int> v[N];
void dfs(int x,int y)
{
    int maxx=0;
    for(int i=0;i<v[y].size();i++)
    {
        if(v[y][i]==x) continue;
        dfs(y,v[y][i]);
        if(a[y]==a[v[y][i]]) continue;
        if(dp[v[y][i]]>dp[y]) maxx=dp[y],dp[y]=dp[v[y][i]];
        else maxx=max(maxx,dp[v[y][i]]);
    }
    dp[y]++;
    ans=max(ans,maxx+dp[y]);
}
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++) cin>>a[i];
    for(int i=1;i<n;i++)
    {
        int x,y;
        cin>>x>>y;
        v[x].push_back(y);
        v[y].push_back(x);
    }
    dfs(0,1);
    cout<<ans;
    return 0;
}
